mapper.select:
SELECT prod.id, prod.category_id, prod.name, prod.subtitle, prod.main_image, prod.images,
       prod.detail, prod.price, prod.stock, prod.status, prod.sales_count, prod.has_sku, prod.created_at, prod.updated_at
FROM mall_product prod

    LEFT JOIN mall_category cat ON prod.category_id = cat.id



        AND MATCH(prod.name, prod.subtitle) AGAINST(#{keyword} IN BOOLEAN MODE)


        AND prod.category_id = #{categoryId}


        AND prod.status = #{status}


ORDER BY ${sortColumn} ${sortDir}

mapper.update:
UPDATE mall_product
category_id = #{categoryId}, name = #{name}, subtitle = #{subtitle}, main_image = #{mainImage}, images = #{images}, detail = #{detail}, price = #{price}, stock = #{stock}, status = #{status}, has_sku = #{hasSku}, updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}

UPDATE mall_product
SET stock = stock - #{quantity},
    updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND stock >= #{quantity}

mapper.select:
SELECT category_id AS categoryId, COUNT(*) AS cnt FROM mall_product WHERE category_id IN
#{categoryId}
GROUP BY category_id
